import{bQ as a,aL as i,u as n,G as t}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"10｜性能调优","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/10-性能调优.md","filePath":"04.MySQL/10-性能调优.md","lastUpdated":null}'),p={name:"04.MySQL/10-性能调优.md"};function l(e,s,h,d,k,o){return i(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="_10-性能调优" tabindex="-1">10｜性能调优 <a class="header-anchor" href="#_10-性能调优" aria-label="Permalink to &quot;10｜性能调优&quot;">​</a></h1><p>前面讲了索引、InnoDB、事务锁。这一篇把它们综合起来——MySQL 变慢时怎么定位、怎么调。</p><p>最关键的一点先说在前面：<strong>MySQL 慢了，不是上来就调参数。</strong> 大多数时候，问题出在 SQL 本身、锁、或物理资源不够，而不是参数不对。从现象出发，按顺序排除，比上来就改配置可靠得多。</p><h2 id="一、性能排查的顺序" tabindex="-1">一、性能排查的顺序 <a class="header-anchor" href="#一、性能排查的顺序" aria-label="Permalink to &quot;一、性能排查的顺序&quot;">​</a></h2><p>MySQL 出问题，按这个顺序查：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 步：系统资源</span></span>
<span class="line"><span>  top / iostat -x 1 / free -h</span></span>
<span class="line"><span>  磁盘和 CPU 有没有被干满。磁盘 await 上百毫秒，先解决磁盘问题。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 步：连接状态</span></span>
<span class="line"><span>  SHOW FULL PROCESSLIST</span></span>
<span class="line"><span>  有没有堆积？卡在什么状态？有没有大量 lock wait？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 3 步：慢 SQL</span></span>
<span class="line"><span>  慢日志或 sys.statement_analysis</span></span>
<span class="line"><span>  什么 SQL 在慢？扫了多少行？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 4 步：锁等待</span></span>
<span class="line"><span>  innodb_trx + innodb_lock_waits</span></span>
<span class="line"><span>  是不是有人在堵着？（第 9 篇讲过）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 5 步：Buffer Pool</span></span>
<span class="line"><span>  Innodb_buffer_pool_read%</span></span>
<span class="line"><span>  是不是物理读太多？（第 8 篇讲过）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 6 步：错误日志</span></span>
<span class="line"><span>  tail error.log</span></span>
<span class="line"><span>  有没有异常？</span></span></code></pre></div><p>每一步都指向一个具体动作——磁盘慢换磁盘、索引没走补索引、锁等待 kill 阻塞源、连接不够限流。查完一圈都说&quot;看起来没问题&quot;，说明突破口还没找到，别放弃继续查。</p><h2 id="二、系统资源-先看硬件够不够" tabindex="-1">二、系统资源：先看硬件够不够 <a class="header-anchor" href="#二、系统资源-先看硬件够不够" aria-label="Permalink to &quot;二、系统资源：先看硬件够不够&quot;">​</a></h2><p>MySQL 跑在机器上，机器资源打满了，再怎么调 MySQL 参数也没用。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # CPU 和内存</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 磁盘 IO，看 %util 和 await</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 内存</span></span></code></pre></div><p>磁盘 <code>await</code> 上百毫秒（正常几毫秒），说明磁盘是瓶颈——要么磁盘本身慢，要么 IO 太密集。MySQL 是 IO 密集型应用，磁盘慢直接影响所有查询。</p><p>CPU 打满了看是哪个进程——如果是 mysqld，看是不是有全表扫描或大量计算的 SQL。内存看 free 和 buffer/cache，Buffer Pool 占大头正常。</p><h2 id="三、连接状态-看连上来的人在干什么" tabindex="-1">三、连接状态：看连上来的人在干什么 <a class="header-anchor" href="#三、连接状态-看连上来的人在干什么" aria-label="Permalink to &quot;三、连接状态：看连上来的人在干什么&quot;">​</a></h2><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW FULL PROCESSLIST;</span></span></code></pre></div><p>列出所有连接在干什么。按状态归类：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user, host, db, command, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">COUNT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cnt</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> information_schema</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">processlist</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GROUP BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user, host, db, command</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cnt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>看到的现象</th><th>大概率原因</th><th>处理</th></tr></thead><tbody><tr><td>大量 Sleep</td><td>连接池空闲连接太多，开了不用</td><td>联系应用缩连接池</td></tr><tr><td>大量 Query 且执行时间长</td><td>慢 SQL 堆积</td><td>找慢 SQL，补索引或限流</td></tr><tr><td>大量 <code>Waiting for lock</code></td><td>锁等待</td><td>找阻塞源，kill</td></tr><tr><td>某来源 IP 连接暴涨</td><td>应用重试风暴或连接泄漏</td><td>限流那个来源</td></tr></tbody></table><h3 id="连接数打满" tabindex="-1">连接数打满 <a class="header-anchor" href="#连接数打满" aria-label="Permalink to &quot;连接数打满&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GLOBAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> STATUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Threads_connected&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;max_connections&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>连接数接近上限，第一反应往往是调大 <code>max_connections</code>。但这只是让更多人排队，不解决根本问题。就像高速堵车，不是把收费站口从 5 个开到 10 个就解决——要看出事的是收费站本身，还是前面的路堵了。</p><p>连接数打满先看连上来的人在干什么——大量 Sleep 是连接池开太大、大量慢 Query 是 SQL 没优化。对症下药，而不是无脑调大连接数。</p><h2 id="四、用-sys-schema-定位慢查询" tabindex="-1">四、用 sys schema 定位慢查询 <a class="header-anchor" href="#四、用-sys-schema-定位慢查询" aria-label="Permalink to &quot;四、用 sys schema 定位慢查询&quot;">​</a></h2><p>8.0 自带的 <code>sys</code> 库，不用记复杂的 <code>information_schema</code> 表关联，直接查：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 最耗时的 10 条 SQL</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sys</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">statement_analysis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total_latency </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 全表扫描的查询</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sys</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">statements_with_full_table_scans</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- IO 压力最大的表</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sys</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">schema_table_statistics</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total_latency </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G</span></span></code></pre></div><p><code>statement_analysis</code> 按 SQL 模式汇总——执行次数、平均耗时、扫的行数。找到最耗时的 SQL，再 EXPLAIN 看执行计划（第 7 篇），补索引或改查询。</p><p><code>statements_with_full_table_scans</code> 直接列出全表扫描的查询——这些是最该优化的，几百万行全扫。</p><h2 id="五、buffer-pool-调优" tabindex="-1">五、Buffer Pool 调优 <a class="header-anchor" href="#五、buffer-pool-调优" aria-label="Permalink to &quot;五、Buffer Pool 调优&quot;">​</a></h2><p>第 8 篇讲过 Buffer Pool 是工作台。调优看命中率：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GLOBAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> STATUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Innodb_buffer_pool_read%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>命中率低于 99%，说明工作台太小。调大 <code>innodb_buffer_pool_size</code>——机器只跑 MySQL 给到内存 70%-80%。8.0+ 在线调不用重启。</p><p>但注意顺序：<strong>先看索引，再看 Buffer Pool。</strong> 查询走全表扫描时，Buffer Pool 再大也没用——扫的还是几百万行。先把索引问题解决（EXPLAIN 看 type 是不是 ALL），再考虑 Buffer Pool。</p><h2 id="六、参数调优的取舍" tabindex="-1">六、参数调优的取舍 <a class="header-anchor" href="#六、参数调优的取舍" aria-label="Permalink to &quot;六、参数调优的取舍&quot;">​</a></h2><p>几个生产常用参数，都有取舍：</p><table tabindex="0"><thead><tr><th>参数</th><th>作用</th><th>调整的取舍</th></tr></thead><tbody><tr><td><code>innodb_buffer_pool_size</code></td><td>Buffer Pool 大小</td><td>调大查询快，但挤占其他进程</td></tr><tr><td><code>innodb_flush_log_at_trx_commit</code></td><td>redo log 刷盘策略</td><td>1 最安全但慢，2 快但崩溃可能丢 1 秒</td></tr><tr><td><code>sync_binlog</code></td><td>binlog 刷盘</td><td>1 最安全，0 快但崩溃可能丢 binlog</td></tr><tr><td><code>max_connections</code></td><td>最大连接数</td><td>调大让更多连接，但不解决慢查询</td></tr></tbody></table><p><code>innodb_flush_log_at_trx_commit=1</code> 和 <code>sync_binlog=1</code> 是&quot;双 1&quot;——最安全的配置，每次事务都刷盘。核心业务库保持双 1，性能有压力时再考虑调低（接受可能丢少量数据的风险）。</p><p>参数调优是最后一步。前面 SQL 优化、索引、锁排查做完，还慢，才考虑调参数。多数情况调参数是给已有问题打补丁，不解决根因。</p><h2 id="七、一句话记排查关键" tabindex="-1">七、一句话记排查关键 <a class="header-anchor" href="#七、一句话记排查关键" aria-label="Permalink to &quot;七、一句话记排查关键&quot;">​</a></h2><p><strong>MySQL 慢 → 先看索引，再看锁，再看 Buffer Pool，最后看磁盘。</strong></p><p>调参数是兜底，不是首选。从现象出发，按顺序排除，找到真正的瓶颈再动手。</p><h2 id="性能调优之后" tabindex="-1">性能调优之后 <a class="header-anchor" href="#性能调优之后" aria-label="Permalink to &quot;性能调优之后&quot;">​</a></h2><p>到这里 InnoDB 部分三篇（存储引擎、事务锁、性能调优）讲完了。接下来是账号权限——谁能连、能干什么。这是安全和合规的基础。</p>`,41)])])}const g=a(p,[["render",l]]);export{c as __pageData,g as default};
